// Input: { pageType, primaryUrl, primaryAllowed, fallbackUrl, fallbackAllowed }
// Collapses the allowed/present checks into an ordered attempt list so the
// rest of the workflow is a single linear try-1-then-try-2 chain.
const item = $input.item.json;
const attempts = [];
if (item.primaryAllowed && item.primaryUrl) attempts.push(item.primaryUrl);
if (item.fallbackAllowed && item.fallbackUrl) attempts.push(item.fallbackUrl);

return [{
  json: {
    pageType: item.pageType,
    attempt1Url: attempts[0] || null,
    attempt2Url: attempts[1] || null
  }
}];

const prep = $('Prepare').item.json;
return [{
  json: {
    pageType: prep.pageType,
    status: 'skipped',
    text: '',
    url: null,
    artifacts: { script_hosts: [], link_hosts: [], meta_generator: null, header_names: [], script_path_markers: [] },
    reason: 'robots_disallowed'
  }
}];

function extractHost(url) {
  let rest = null;
  if (url.startsWith('//')) {
    rest = url.slice(2);
  } else if (/^https?:\/\//i.test(url)) {
    rest = url.replace(/^https?:\/\//i, '');
  } else {
    return null;
  }
  return rest.split(/[\/?#]/)[0] || null;
}

function extractArtifacts(html, headers) {
  const PATH_MARKERS = ['/_next/static/', '/wp-content/', '/wp-includes/', 'unpkg.com/react', 'jsdelivr.net/npm/react'];
  const scriptHosts = new Set();
  const linkHosts = new Set();
  const pathMarkers = new Set();

  const scriptRe = /<script\b[^>]*\bsrc=["']([^"']+)["'][^>]*>/gi;
  let m;
  while ((m = scriptRe.exec(html))) {
    const src = m[1];
    const host = extractHost(src);
    if (host) scriptHosts.add(host);
    for (const marker of PATH_MARKERS) {
      if (src.includes(marker)) pathMarkers.add(marker);
    }
  }

  const linkRe = /<link\b[^>]*\bhref=["']([^"']+)["'][^>]*>/gi;
  while ((m = linkRe.exec(html))) {
    const host = extractHost(m[1]);
    if (host) linkHosts.add(host);
  }

  let metaGenerator = null;
  const metaRe = /<meta\b[^>]*>/gi;
  while ((m = metaRe.exec(html))) {
    const tag = m[0];
    if (/\bname=["']generator["']/i.test(tag)) {
      const contentMatch = tag.match(/\bcontent=["']([^"']*)["']/i);
      if (contentMatch) { metaGenerator = contentMatch[1]; break; }
    }
  }

  return {
    script_hosts: Array.from(scriptHosts),
    link_hosts: Array.from(linkHosts),
    meta_generator: metaGenerator,
    header_names: headers ? Object.keys(headers) : [],
    script_path_markers: Array.from(pathMarkers)
  };
}

const html = ($json.body ?? $json.data ?? '').toString();
const url = $('Prepare').item.json.attempt1Url;
const CHAR_CAP = 4000;
const MIN_CONTENT_CHARS = 80;

const text = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, CHAR_CAP);

const status = text.length >= MIN_CONTENT_CHARS ? 'ok' : 'failed';
const artifacts = extractArtifacts(html, $json.headers);

return [{
  json: {
    pageType: $('Prepare').item.json.pageType,
    status,
    text: status === 'ok' ? text : '',
    url,
    artifacts,
    ...(status === 'failed' ? { reason: 'empty_content' } : {})
  }
}];

